#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use URI;

my $cgi = CGI->new;
my $next_param = $cgi->param('next');

# Allowlist of safe redirect paths
my @allowed_paths = (
    '/dashboard',
    '/profile',
    '/settings',
    '/account',
    '/home',
    '/index'
);

my $redirect_url = '/';

# Check if next parameter exists and is a valid URL
if ($next_param) {
    # Parse the URL to check if it's a valid URI
    my $uri = URI->new($next_param);
    
    # If it's a relative path, check against allowlist
    if (!$uri->scheme && !$uri->host) {
        # Check if the path is in our allowlist
        my $path = $uri->path;
        foreach my $allowed_path (@allowed_paths) {
            if ($path eq $allowed_path) {
                $redirect_url = $next_param;
                last;
            }
        }
    }
    # If it's an absolute URL, check if it's from our domain
    elsif ($uri->scheme && $uri->host) {
        my $host = $uri->host;
        # Allow only our own domain
        if ($host eq 'example.com' || $host eq 'www.example.com') {
            $redirect_url = $next_param;
        }
    }
}

print "Location: $redirect_url\n\n";